fts-trigram-index-redirect.map:
function (doc) {
  if (doc.type === "redirect" && doc.fts) {
    for (var i = 0; i < doc.fts.length; i++) {
      var e = doc.fts[i];
      var c = e.indexOf(":", 3);
      emit(e.substring(0, c), {
        memberOf: doc.memberOf || [],
        slug: doc.slug || null,
        toSlug: doc.toSlug || null,
        updatedTimeUtc: doc.updatedTimeUtc || null
      });
    }
  }
}
